import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"明日方舟集成战略","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/游戏/明日方舟肉鸽.md","filePath":"ccc/游戏/明日方舟肉鸽.md"}`),a={name:`ccc/游戏/明日方舟肉鸽.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="明日方舟集成战略" tabindex="-1">明日方舟集成战略 <a class="header-anchor" href="#明日方舟集成战略" aria-label="Permalink to “明日方舟集成战略”">​</a></h1><h2 id="界园" tabindex="-1">界园 <a class="header-anchor" href="#界园" aria-label="Permalink to “界园”">​</a></h2><p>二：洞里【传说】30源石腚换藏品，战斗中出现龙脚，打掉后掉落二结局藏品。第五层结尾打二结局BOSS。龙脚会踩3X3范围内我方干员最多的位置。</p><p>三：洞里【杂疑】要5名伺烛客。获得三结局藏品【忘生珍珑】，在指点迷津打特殊作战，进入第六层三结局。</p><p>先锋：伊内丝</p><p>狙击：<strong>维什戴尔</strong>、</p><p>特种：新约能天使、缄默德克萨斯、麒麟R夜刀</p><p>辅助：<strong>酒神</strong>、电弧</p><p>近卫：司霆惊蛰</p><p>医疗：凯尔希</p><p>术士：荒芜拉普兰德、</p><p>13层进洞3烛火，245进洞5烛火。</p><p>一层打架+买招募券，进洞发育不打架。</p><p>二层券用光，尽量不进洞。</p><p>三层优先走【指点迷津】用券。</p><p>四五层进洞打架。</p><h2 id="萨卡兹的无终奇语" tabindex="-1">萨卡兹的无终奇语 <a class="header-anchor" href="#萨卡兹的无终奇语" aria-label="Permalink to “萨卡兹的无终奇语”">​</a></h2><p><strong><a href="https://www.bilibili.com/video/BV1q4421D7KQ" target="_blank" rel="noreferrer">小鬼卡比的攻略</a></strong>；<a href="https://www.bilibili.com/video/BV1jUw3eoEGJ" target="_blank" rel="noreferrer">柠檬味的小小猪</a>；</p><h3 id="结局要点" tabindex="-1">结局要点 <a class="header-anchor" href="#结局要点" aria-label="Permalink to “结局要点”">​</a></h3><p><a href="https://www.bilibili.com/video/BV1yw4m1k7eT" target="_blank" rel="noreferrer">二</a>：2层【命运所指】，任意【去伪存真】合并纯白花瓣与无字地契。</p><blockquote><p>真伤，妮芙+塑心蛮干；黍/拉人特种拉二阶段特雷西斯；30血放生特雷西斯。</p></blockquote><p><a href="https://www.bilibili.com/video/BV1aW42197Ut" target="_blank" rel="noreferrer">三</a>：解锁【失与得】，选“一个方盒”（<strong>刷新</strong>节点变【命运所指】，<strong>2个构想</strong>进树洞【诡谲断章】）。</p><p>树洞中【命运所指】选“时与光”触发。时代会更频繁。打完1或2结局BOSS后进第六层。</p><ul><li>尽可能堆高干员血量，+血量灵感。</li><li>高台迷彩不会受到BOSS全屏伤害。2x<strong>筑墙</strong>可合成。（<strong>筑墙</strong>部署后获得1层护盾）</li><li>放在圣盾周围减伤害。120s或自动机碰到圣盾会消失。</li><li></li><li>带控制法师堵上面的门，清自动机。</li><li>最下方悬浮怪，控制干员处理。</li><li></li><li>快活骗炮兵子弹。</li><li>最后一波出“门”，击倒时带走最后一个部署的干员。</li><li>boss二阶段前先攒技能，留技能清第三波。</li></ul><blockquote><p>45,62,BOSS不进入二阶段90s后出第三波。盾奶/快活打年糕拖到小怪刷完。</p><p>30血放生圣爹。</p><p>妮芙+回转手，永控。</p></blockquote><p><a href="https://www.bilibili.com/video/BV1ms14Y6EPB" target="_blank" rel="noreferrer">四</a>：【失与得】选一片莲瓣，消耗所有源石锭，战斗获得经验源石锭减半。最好第四层拿。</p><p>任意【狭路相逢】（第五层必有），<strong>2构想</strong>。将花瓣掷入故事。然后打船。获得藏品，领袖与精英敌人生命+50%，开启第六层。</p><blockquote><p>刚需全图奶，纯艾，赫默。</p><p>妮芙+回转手，仇白1技能+攻速，永控。</p></blockquote><p><a href="https://www.bilibili.com/video/BV1cawNe5Ebs" target="_blank" rel="noreferrer">五</a>：【不期而遇】空无前兆，试着接受它，收藏品预言显像。</p><p>任意作战都会刷怪“终曲合声”，进蓝门-1生命值，额外获得任意收藏品，怪血量继承。法伤全图普攻，无法阻挡。</p><p>击杀得到思绪“绝望”。【去伪存真】+构想可以合成。绝望》拯救》停止，难度依次提升。</p><p>【孤注一掷】铸造钥匙，”无终之钥“开启5结局。负面藏品，终结的xx（部署费用+2，敌人减物法伤20%）(敌人攻击力+20%)（5结局关底出现额外敌人）。</p><p>135连打延长发育。也可以45连打。</p><ul><li>部署干员被封印，球碰一下解封。</li><li>魔王普攻伤害很高。</li><li></li><li>有名的精英(其他结局boss)进蓝门或被消灭就触发清场，被清掉的怪直接扣目标生命。</li><li>用控制技能拖住或放生后马上清杂。</li></ul><blockquote><p>多拿快活先锋，快活挡球。</p><p>高攻速下，傀影影子抗魔王兔。</p></blockquote><h3 id="干员抓取" tabindex="-1">干员抓取 <a class="header-anchor" href="#干员抓取" aria-label="Permalink to “干员抓取”">​</a></h3><p>加粗可能可用于开局。</p><h4 id="先锋" tabindex="-1">先锋 <a class="header-anchor" href="#先锋" aria-label="Permalink to “先锋”">​</a></h4><p>伊内斯；<strong>晓歌；</strong>桃金娘；</p><blockquote><p>豆苗，低难度好用，补阻挡，快活。</p></blockquote><h4 id="近卫" tabindex="-1">近卫 <a class="header-anchor" href="#近卫" aria-label="Permalink to “近卫”">​</a></h4><p><strong>乌尔比安+银灰</strong>；玛恩纳+赫德雷；仇白；</p><blockquote><p>休谟斯，前期单守，清杂。石英，需要医疗，前期单守+清杂；</p><p>银灰；芳汀；宴；刻刀：打刺。</p><p>维娜，真伤+吃文明存续，二五结局。</p></blockquote><h4 id="重装" tabindex="-1">重装 <a class="header-anchor" href="#重装" aria-label="Permalink to “重装”">​</a></h4><p>黍（2结局）；古米；角峰；</p><p>号角；</p><blockquote><p>菲莱，切刺；重辅开局，安洁莉娜+菲莱。</p><p>涤火杰西卡+烟花手藏品。</p></blockquote><h4 id="辅助" tabindex="-1">辅助 <a class="header-anchor" href="#辅助" aria-label="Permalink to “辅助”">​</a></h4><p><strong>塑心；</strong>波登可；深海色，罗比拉塔（补阻挡）；巫恋；</p><blockquote><p><strong>安洁莉娜</strong>（特限模组）+抠挠手，灵知也可以吃。</p></blockquote><h4 id="狙击" tabindex="-1">狙击 <a class="header-anchor" href="#狙击" aria-label="Permalink to “狙击”">​</a></h4><p><strong>维什戴尔；</strong></p><p>寒芒克洛丝；铅踝；流星；松果；白雪；</p><blockquote><p>精二维什戴尔+美愿时代，在得偿所愿能稳定拿轰鸣手。</p><p><strong>迷迭香</strong>，承曦格雷伊：可以吃维什戴尔藏品。迷迭香特限模组可以吃术士藏品，开局实用。</p><p><strong>莱伊</strong>可开局，后期乏力。</p><p>梅，小控制；</p></blockquote><h4 id="医疗" tabindex="-1">医疗 <a class="header-anchor" href="#医疗" aria-label="Permalink to “医疗”">​</a></h4><p>纯烬艾雅法拉；蜜莓/哈洛德；<strong>凯尔希</strong>（特限模组）；医疗阿米娅；赫墨；苏苏洛/嘉维尔；调香师；</p><blockquote><p>华法琳，拐。</p></blockquote><h4 id="术士" tabindex="-1">术士 <a class="header-anchor" href="#术士" aria-label="Permalink to “术士”">​</a></h4><p><strong>荒芜拉普兰德</strong>+澄闪；逻各斯+妮芙；卡达；</p><blockquote><p>玛露西尔，寒檀，蹭波纹手（澄闪）。</p><p>深靛，小控制。夜烟，小减抗。</p></blockquote><h4 id="特种" tabindex="-1">特种 <a class="header-anchor" href="#特种" aria-label="Permalink to “特种”">​</a></h4><p><strong>阿斯卡伦</strong>；锡人；<strong>艾拉；</strong>砾；伊桑；</p><p>缄默德克萨斯；麒麟R夜刀；傀影；</p><blockquote><p>歌蕾蒂亚；</p><p>云迹，打飞机，打船。</p><p>-12秒再部署灵感，卡夫卡一技能永控。</p></blockquote><h3 id="遗愿" tabindex="-1"><a href="https://prts.wiki/w/%E8%90%A8%E5%8D%A1%E5%85%B9%E7%9A%84%E6%97%A0%E7%BB%88%E5%A5%87%E8%AF%AD/%E4%BD%9A%E6%95%A3%E6%80%9D%E7%BB%B4%E8%BE%91%E5%BD%95#%E7%81%B5%E6%84%9F" target="_blank" rel="noreferrer">遗愿</a> <a class="header-anchor" href="#遗愿" aria-label="Permalink to “遗愿”">​</a></h3><p><strong>离迁</strong>使用后，下次战斗所有远程干员获得迷彩，<a href="https://prts.wiki/w/%E8%90%A8%E5%8D%A1%E5%85%B9%E7%9A%84%E6%97%A0%E7%BB%88%E5%A5%87%E8%AF%AD/%E4%BD%9A%E6%95%A3%E6%80%9D%E7%BB%B4%E8%BE%91%E5%BD%95#%E7%AD%91%E5%A2%99" target="_blank" rel="noreferrer">筑墙</a>×2。（部署后获得1层护盾）</p>`,66)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};